package com.oceandatum.quality.common.rulebase;

import java.util.HashMap;
import java.util.Map;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import cn.hutool.core.util.StrUtil;


public class IDCardRule extends AbstractRule {

    private static final Map<Object,Object> CITYS = new HashMap<Object,Object>() {{
        put("11", "北京");put("12", "天津");put("13", "河北");put("14", "山西");put("15", "内蒙古");
        put("21", "辽宁");put("22", "吉林");put("23", "黑龙江");put("31", "上海");put("32", "江苏");
        put("33", "浙江");put("34", "安徽");put("35", "福建");put("36", "江西");put("37", "山东");
        put("41", "河南");put("42", "湖北");put("43", "湖南");put("44", "广东");put("45", "广西");
        put("46", "海南");put("50", "重庆");put("51", "四川");put("52", "贵州");put("53", "云南");
        put("54", "西藏");put("61", "陕西");put("62", "甘肃");put("63", "青海");put("64", "宁夏");
        put("65", "新疆");put("71", "台湾");put("81", "香港");put("82", "澳门");put("91", "国外");
    }};
    private static final String reg = '(^\\d{17}(\\d|X|x)$)';
    // 15位的身份证
    private static final String re_fifteen = '(\\d{6})(\\d{2})(\\d{2})(\\d{2})(\\d{3})';
    // 18位的身份证
    private static final String re_eighteen = '(\\d{6})(\\d{4})(\\d{2})(\\d{2})(\\d{3})([0-9]|X|x)';

    private static final int[] arrInt = [7, 9, 10, 5, 8, 4, 2, 1, 6, 3, 7, 9, 10, 5, 8, 4, 2];

    private static final String[] arrCh = ["1", "0", "X", "9", "8", "7", "6", "5", "4", "3", "2"];
    @Override
    public boolean doCheck(String value) {
        return this.checkCard(value);
    }

    @Override
    public boolean doCheck(String value, String target) {
        return false;
    }

    // 判断位数
    public static boolean isCardNo(String obj) {
        //身份证号码为15位或者18位，15位时全为数字，18位前17位为数字，最后一位是校验位，可能为数字或字符X
        // String reg = "(^\\d{15}$)|(^\\d{17}(\\d|X)$)";
        if(Pattern.matches(reg, obj)){
            return true;
        }
        return false;
    }
    // 判断省份
    public static boolean checkProvince(String obj) {
        String province = obj.substring(0,2);
        if(CITYS.get(province) == null){
            return false;
        }
        return true;
    }
    // 判断生日
    public static boolean checkBirthday(String obj) {
        if(StrUtil.isEmpty(obj)){
            return false;
        }
        int len = obj.length();
        //身份证15位时，次序为省（3位）市（3位）年（2位）月（2位）日（2位）校验位（3位），皆为数字
        if(len == 15){
            // String re_fifteen = "^(\\d{6})(\\d{2})(\\d{2})(\\d{2})(\\d{3})$";
            Pattern pattern = Pattern.compile(re_fifteen);//编译正则表达式(\w+),?
            Matcher matcher = pattern.matcher(obj);
            if(!matcher.find()) {
                return false;
            }


            String year = matcher.group(2);
            String month = matcher.group(3);
            String day = matcher.group(4);
            Date birthday = null;
            try{
                birthday = new Date("19" + year + "/" + month + "/" + day);
            }catch (Exception e){
                return  false;
            }

            return verifyBirthday(Integer.parseInt("19" + year), Integer.parseInt(month), Integer.parseInt(day), birthday);
        }
        //身份证18位时，次序为省（3位）市（3位）年（4位）月（2位）日（2位）校验位（4位），校验位末尾可能为X
        if(len == 18){
            // String re_eighteen = "(\\d{6})(\\d{4})(\\d{2})(\\d{2})(\\d{3})([0-9]|X|x)";
            Pattern pattern = Pattern.compile(re_eighteen);//编译正则表达式(\w+),?
            Matcher matcher = pattern.matcher(obj);

            if(!matcher.find()) {
                /*
                 * String result = matcher.group(); if(matcher.groupCount() > 0){ for(int i = 1;
                 * i <= matcher.groupCount(); ++i){ String dd =
                 * matcher.group(i);//当前匹配结果中第i个捕获结果，i:1, 2, 3… } }
                 */
                return false;
            }

            // matcher.group();//当前匹配结果
            // matcher.start();//当前匹配结果首字符在目标字符串中的索引位置index
            // matcher.end();//当前匹配结果末位字符在目标字符串中的索引位置index+1
            // matcher.groupCount();//正则表达式中捕获项个数
            // if(matcher.groupCount() > 0){
            //    for(int i = 1; i <= matcher.groupCount(); ++i){
            //        matcher.group(i);//当前匹配结果中第i个捕获结果，i:1, 2, 3…
            //    }
            //}

            String year = matcher.group(2);
            String month = matcher.group(3);
            String day = matcher.group(4);

            Date birthday = new Date(year + '/' + month + '/' + day);
            return verifyBirthday(Integer.parseInt(year), Integer.parseInt(month), Integer.parseInt(day), birthday);
        }
        return false;
    }

    private static String changeFivteenToEighteen(String obj){
        int leng = obj.length();
        if(leng == 15) {
            // int arrInt[] = {7, 9, 10, 5, 8, 4, 2, 1, 6, 3, 7, 9, 10, 5, 8, 4, 2};
            // String arrCh[] = {"1", "0", "X", "9", "8", "7", "6", "5", "4", "3", "2"};
            int cardTemp = 0, i;
            obj = obj.substring(0, 6) + "19" + obj.substring(6, leng);
            for(i = 0; i < 17; i ++){
                cardTemp += Integer.parseInt(obj.substring(i, i + 1)) * arrInt[i];
            }
            obj += arrCh[cardTemp % 11];
            return obj;
        }
        return obj;
    }

    private static boolean verifyBirthday(int year,int month, int day,Date birthday){
        Date now = new Date();
        int nowYear = now.getYear() + 1900;
        int birthYear = birthday.getYear() + 1900;
        //年月日是否合理
        if(birthYear == year && (birthday.getMonth() + 1) == month && birthday.getDate() == day){
            //判断年份的范围（3岁到100岁之间)
            int time = nowYear - year;
            if(time >= 0 && time <= 130){
                return true;
            }
            return false;
        }
        return false;
    }


    // 检验位的检测
    public static boolean checkParity(String obj) {
        obj = changeFivteenToEighteen(obj);//15位转18位
        int len = obj.length();
        if(len == 18) {
            // int arrInt[] = {7, 9, 10, 5, 8, 4, 2, 1, 6, 3, 7, 9, 10, 5, 8, 4, 2};
            // String arrCh[] = {"1", "0", "X", "9", "8", "7", "6", "5", "4", "3", "2"};
            int cardTemp = 0, i;
            String valnum = "";
            for(i = 0; i < 17; i ++) {
                cardTemp += Integer.parseInt(obj.substring(i, i + 1)) * arrInt[i];
            }
            valnum = arrCh[cardTemp % 11];
            if(valnum.equalsIgnoreCase(obj.substring(17, 18))){
                return true;
            }
            return false;
        }
        return false;
    }
    /**
     *
     * @Title: checkCard
     * @Description:(身份证规范性检查)
     * @author dds
     * @Date 2019年10月14日  下午2:25:03
     * @param obj
     * @return boolean    返回类型
     */
    public  boolean checkCard(String obj) {
        try{
            if(obj==null){
                return false;
            }
            obj = obj.trim();

            if("".equals(obj)) { // 判空处理
                return false;
            }
            if(!isCardNo(obj)) { // 判断位数
                return false;
            }
            if(!checkProvince(obj)) { // 判断省份
                return false;
            }
            if(!checkBirthday(obj)) { // 判断生日
                return false;
            }
            if(!checkParity(obj)) { // 检验位的检测
                return false;
            }
        }catch (Exception e){
            return  false;
        }
        return true;
    }
}
